+    #[test]
+    fn test_export_bytes_are_readable_by_external_sqlite() {
+        let conn = Connection::open(":memory:").unwrap();
+        conn.execute("CREATE TABLE export_t (id INTEGER PRIMARY KEY, name TEXT);")
+            .unwrap();
+        conn.execute("INSERT INTO export_t VALUES (1, 'alpha'), (2, 'beta');")
+            .unwrap();
+
+        let bytes = conn.export_bytes().unwrap();
+        let dir = tempfile::tempdir().unwrap();
+        let db_path = dir.path().join("exported.db");
+        std::fs::write(&db_path, bytes).unwrap();
+
+        let sqlite = rusqlite::Connection::open(&db_path).unwrap();
+        let mut stmt = sqlite
+            .prepare("SELECT id, name FROM export_t ORDER BY id;")
+            .unwrap();
+        let rows = stmt
+            .query_map([], |row| {
+                Ok((
+                    row.get::<_, i64>(0).unwrap(),
+                    row.get::<_, String>(1).unwrap(),
+                ))
+            })
+            .unwrap()
+            .collect::<std::result::Result<Vec<_>, _>>()
+            .unwrap();
+
+        assert_eq!(rows, vec![(1, "alpha".to_owned()), (2, "beta".to_owned())]);
+    }
+
+    #[test]
+    fn test_import_bytes_accepts_external_sqlite_image() {
+        let dir = tempfile::tempdir().unwrap();
+        let db_path = dir.path().join("external.db");
+
+        let sqlite = rusqlite::Connection::open(&db_path).unwrap();
+        sqlite
+            .execute_batch(
+                "
+                PRAGMA page_size = 8192;
+                VACUUM;
+                CREATE TABLE import_t (id INTEGER PRIMARY KEY, name TEXT);
+                INSERT INTO import_t VALUES (1, 'alpha'), (2, 'beta');
+                ",
+            )
+            .unwrap();
+        drop(sqlite);
+
+        let bytes = std::fs::read(&db_path).unwrap();
+        let imported = Connection::import_bytes(&bytes).unwrap();
+        let rows = imported
+            .query("SELECT id, name FROM import_t ORDER BY id;")
+            .unwrap();
+
+        assert_eq!(rows.len(), 2);
+        assert_eq!(rows[0].values()[1], SqliteValue::Text("alpha".into()));
+        assert_eq!(rows[1].values()[1], SqliteValue::Text("beta".into()));
+    }
